package ClassandObject;

public class localVariable {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		localVariable obj=new localVariable();
		obj.add();
	}
	
	public void add()
	{
		int a=10;    //local variable
		int b=20;
		int c=a+b;
		System.out.println(c);
	}

}
